Here's a complete example with both `DataRow` and `DynamicData` approaches:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
public class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // --- DataRow: inline constant values ---

    [TestMethod]
    [DataRow(1, 10.00, 10.00)]
    [DataRow(5, 3.50, 17.50)]
    [DataRow(0, 99.99, 0.00)]
    [DataRow(100, 0.01, 1.00)]
    public void CalculateTotal_ReturnsExpected(int quantity, double unitPrice, double expected)
    {
        var result = _calculator.CalculateTotal(quantity, (decimal)unitPrice);
        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(100.00, 0.10, 90.00)]   // 10% off
    [DataRow(100.00, 0.00, 100.00)]  // no discount
    [DataRow(50.00, 0.50, 25.00)]    // 50% off
    [DataRow(200.00, 1.00, 0.00)]    // 100% off
    public void ApplyDiscount_ReturnsExpected(double price, double discount, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discount);
        Assert.AreEqual((decimal)expected, result);
    }

    // --- DynamicData: complex/non-constant test cases ---

    [TestMethod]
    [DynamicData(nameof(BulkOrderCases), DynamicDataSourceType.Method)]
    public void CalculateTotal_BulkOrders_ReturnsExpected(
        int quantity, decimal unitPrice, decimal expected)
    {
        var result = _calculator.CalculateTotal(quantity, unitPrice);
        Assert.AreEqual(expected, result);
    }

    private static IEnumerable<object[]> BulkOrderCases()
    {
        yield return new object[] { 1000, 5.99m, 5990.00m };
        yield return new object[] { 999, 0.01m, 9.99m };
        yield return new object[] { int.MaxValue, 0m, 0m };
    }

    [TestMethod]
    [DynamicData(nameof(InvalidDiscountCases), DynamicDataSourceType.Method)]
    public void ApplyDiscount_InvalidInput_Throws(decimal price, decimal discount)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(price, discount));
    }

    private static IEnumerable<object[]> InvalidDiscountCases()
    {
        yield return new object[] { 100m, -0.01m };  // negative discount
        yield return new object[] { 100m, 1.01m };   // over 100%
        yield return new object[] { -10m, 0.10m };   // negative price
    }
}
```

**Key best practices shown:**

| Practice | Detail |
|----------|--------|
| `DataRow` | Best for simple, inline constant values (note: `decimal` literals aren't allowed—use `double` and cast) |
| `DynamicData` | Use when you need `decimal`, complex objects, or computed test data |
| `DynamicDataSourceType.Method` | Preferred over `Property` for lazy evaluation via `yield return` |
| Descriptive method names | `Method_Scenario_Expected` naming convention |
| Edge cases | Zero values, boundaries, invalid inputs |
| Exception testing | Separate test method for invalid inputs with `ThrowsException` |

To add display names for better test explorer output, you can annotate `DynamicData` with:

```csharp
[DynamicData(nameof(BulkOrderCases), DynamicDataSourceType.Method,
    DynamicDataDisplayName = nameof(GetDisplayName))]

private static string GetDisplayName(MethodInfo _, object[] data)
    => $"Qty={data[0]}, Price={data[1]} → {data[2]}";
```
